sql:
SELECT player_name, team
FROM players
WHERE player_id IN (SELECT DISTINCT player_id FROM player_performance WHERE hits > 0);

SELECT players.player_name, game_logs.game_date, game_logs.opponent, game_logs.result, game_logs.location
FROM players
INNER JOIN game_logs ON players.player_id = game_logs.player_id;

SELECT SUM(total_pitches) AS total_pitches_thrown
FROM pitches_stats
WHERE player_id = 0;

SELECT total_pitches, ba, iso, babip, slg, woba, xwoba, pitch_type, season
FROM pitches_stats
WHERE player_id = 0 AND season = '2023';

SELECT DISTINCT p.player_name, ps.pitch_type
FROM players p
INNER JOIN pitches_stats ps ON p.player_id = ps.player_id;

SELECT AVG(total_pitches) AS average_pitches
FROM pitches_stats
WHERE player_id = 0 AND season = '2023';

SELECT MAX(games_played) AS highest_games_played
FROM (
    SELECT player_id, COUNT(*) AS games_played
    FROM game_logs
    GROUP BY player_id
) AS player_game_counts;
